INSERT INTO public.recipes ("id", "title", "description", "instructions", "category", "difficulty", "image_url", "ingredients", "author_id", "created_at", "source_url") VALUES ('5abc170b-a0f7-4974-b1f8-ee6952d92be4', 'Frango com Quiabo Mineiro', 'Receita tradicional caipira, cheia de sabor e afeto.', '1. Frite o quiabo até sair a baba e reserve.
2. Refogue o frango até ficar bem dourado.
3. Adicione temperos, água e deixe cozinhar.
4. Quando o frango estiver macio, adicione o quiabo e deixe apurar.', 'Aves', 'Média', 'https://images.unsplash.com/photo-1604908176997-125f25cc6f3d?w=800&h=400&fit=crop', '[{"name": "Frango", "quantity": "1kg"}, {"name": "Quiabo", "quantity": "500g"}, {"name": "Cebola", "quantity": "1 unidade"}, {"name": "Alho", "quantity": "3 dentes"}]', '47c981d3-ef57-420f-9d99-71c76b3b7d09', '2026-05-09T00:29:46.398624+00:00', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes ("id", "title", "description", "instructions", "category", "difficulty", "image_url", "ingredients", "author_id", "created_at", "source_url") VALUES ('8a3efaf2-93c1-4e38-a044-89fbaed783f1', 'Lasanha à Bolonhesa Especial', 'Camadas generosas de massa, carne e muito queijo.', '1. Prepare o molho bolonhesa bem suculento.
2. Em um refratário, intercale camadas de molho, massa, presunto e queijo.
3. Repita até acabar os ingredientes.
4. Leve ao forno médio por 30 minutos até gratinar.', 'Massas', 'Média', 'https://images.unsplash.com/photo-1551183053-bf91a1d81141?w=800&h=400&fit=crop', '[{"name": "Massa de Lasanha", "quantity": "500g"}, {"name": "Carne Mo\u00edda", "quantity": "500g"}, {"name": "Molho de Tomate", "quantity": "2 sach\u00eas"}, {"name": "Queijo Mussarela", "quantity": "300g"}]', '47c981d3-ef57-420f-9d99-71c76b3b7d09', '2026-05-09T00:29:46.398624+00:00', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes ("id", "title", "description", "instructions", "category", "difficulty", "image_url", "ingredients", "author_id", "created_at", "source_url") VALUES ('af5ad8a6-19fc-4ad7-b5da-f84cad077834', 'Bolo de Cenoura Fofinho', 'O segredo da vovó para o bolo mais fofo com calda crocante.', '1. Bata as cenouras, ovos e óleo no liquidificador.
2. Misture o açúcar e a farinha em uma tigela.
3. Una as misturas e acrescente o fermento.
4. Asse em forno médio por 40 minutos.', 'Doces e sobremesas', 'Fácil', 'https://images.unsplash.com/photo-1606890737304-57a1ca8a5b62?w=800&h=400&fit=crop', '[{"name": "Cenoura", "quantity": "3 unidades"}, {"name": "\u00d3leo", "quantity": "1 x\u00edcara"}, {"name": "Ovos", "quantity": "3 unidades"}, {"name": "Chocolate em P\u00f3", "quantity": "1 x\u00edcara"}]', '47c981d3-ef57-420f-9d99-71c76b3b7d09', '2026-05-09T00:29:46.398624+00:00', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes ("id", "title", "description", "instructions", "category", "difficulty", "image_url", "ingredients", "author_id", "created_at", "source_url") VALUES ('0a591b18-bfd0-431d-a779-468638b81709', 'Pudim de Leite Condensado', 'A sobremesa número 1 do Brasil, sem furinhos e deliciosa.', '1. Prepare a calda caramelizando o açúcar.
2. Bata o leite condensado, leite e ovos no liquidificador.
3. Despeje na forma caramelizada.
4. Cozinhe em banho-maria por 45 minutos.', 'Doces e sobremesas', 'Média', 'https://images.unsplash.com/photo-1528975604071-b4dc52a2d18c?w=800&h=400&fit=crop', '[{"name": "Leite Condensado", "quantity": "1 lata"}, {"name": "Leite", "quantity": "1 medida"}, {"name": "Ovos", "quantity": "3 unidades"}, {"name": "A\u00e7\u00facar", "quantity": "1 x\u00edcara"}]', '47c981d3-ef57-420f-9d99-71c76b3b7d09', '2026-05-09T00:29:46.398624+00:00', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes ("id", "title", "description", "instructions", "category", "difficulty", "image_url", "ingredients", "author_id", "created_at", "source_url") VALUES ('0292decc-95c3-4c18-8707-495fc7daa3cb', 'Fricassê de Frango Cremoso', 'Prático e irresistível com cobertura de batata palha.', '1. Bata o milho com requeijão e creme de leite no liquidificador.
2. Refogue o frango desfiado com temperos.
3. Misture o creme ao frango e coloque em uma travessa.
4. Cubra com mussarela e batata palha e leve ao forno.', 'Aves', 'Fácil', 'https://images.unsplash.com/photo-1626082896492-766af4eb6501?w=800&h=400&fit=crop', '[{"name": "Frango Desfiado", "quantity": "500g"}, {"name": "Milho Verde", "quantity": "1 lata"}, {"name": "Requeij\u00e3o", "quantity": "1 copo"}, {"name": "Batata Palha", "quantity": "100g"}]', '47c981d3-ef57-420f-9d99-71c76b3b7d09', '2026-05-09T00:29:46.398624+00:00', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes ("id", "title", "description", "instructions", "category", "difficulty", "image_url", "ingredients", "author_id", "created_at", "source_url") VALUES ('0c9fa34d-7e87-4aee-afa2-24e3bc0bd41c', 'Macarrão Carbonara Rápido', 'A autêntica receita italiana pronta em 15 minutos.', '1. Cozinhe o macarrão al dente.
2. Frite o bacon até ficar crocante.
3. Misture os ovos com o queijo ralado.
4. Com o fogo desligado, junte o macarrão quente ao bacon e à mistura de ovos, mexendo rápido.', 'Massas', 'Fácil', 'https://images.unsplash.com/photo-1612874742237-6526221588e3?w=800&h=400&fit=crop', '[{"name": "Macarr\u00e3o Espaguete", "quantity": "500g"}, {"name": "Bacon", "quantity": "200g"}, {"name": "Ovos", "quantity": "3 unidades"}, {"name": "Queijo Parmes\u00e3o", "quantity": "100g"}]', '47c981d3-ef57-420f-9d99-71c76b3b7d09', '2026-05-09T00:29:46.398624+00:00', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes ("id", "title", "description", "instructions", "category", "difficulty", "image_url", "ingredients", "author_id", "created_at", "source_url") VALUES ('7c3dd2c7-e3cd-40b4-b589-a4bc96a0bcb9', 'Escondidinho de Carne Seca', 'Purê de mandioca cremoso com recheio de carne seca bem temperada.', '1. Prepare o purê de mandioca com leite e manteiga.
2. Refogue a carne seca desfiada com cebola e alho.
3. Em um refratário, coloque metade do purê, a carne e cubra com o restante.
4. Polvilhe queijo e leve para gratinar.', 'Carnes', 'Média', 'https://images.unsplash.com/photo-1544025162-d76694265947?w=800&h=400&fit=crop', '[{"name": "Carne Seca", "quantity": "500g"}, {"name": "Mandioca", "quantity": "1kg"}, {"name": "Leite", "quantity": "1 x\u00edcara"}, {"name": "Manteiga", "quantity": "2 colheres"}]', '47c981d3-ef57-420f-9d99-71c76b3b7d09', '2026-05-09T00:29:46.398624+00:00', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes ("id", "title", "description", "instructions", "category", "difficulty", "image_url", "ingredients", "author_id", "created_at", "source_url") VALUES ('30e61aa7-2aff-4143-872e-98f060d61eae', 'Chef IA: LEITE CONDENSADO Criativo', 'Esta receita foi cuidadosamente elaborada por nosso algoritmo de gastronomia para destacar os sabores de: LEITE CONDENSADO, MARACUJA
. Uma combinação harmoniosa de texturas e aromas para uma experiência única.', '1. Preparação Inicial: Comece organizando todos os ingredientes: LEITE CONDENSADO, MARACUJA
. Lave e corte os vegetais e proteínas em tamanhos uniformes.
2. Base de Sabor: Em uma panela aquecida com um fio de azeite, doure os ingredientes principais começando pelos que exigem mais tempo de cocção.
3. Desenvolvimento: Adicione os temperos de sua preferência e deixe os sabores se integrarem em fogo médio. Se necessário, adicione um pouco de água ou caldo para manter a umidade.
4. Finalização: Cozinhe até que a textura esteja ao seu gosto. Desligue o fogo e adicione ervas frescas por cima antes de servir.
5. Serviço: Disponha em um prato fundo para preservar o calor e finalize com um toque de pimenta moída na hora.', 'Inovação IA', 'Média', 'https://images.unsplash.com/photo-1546069901-ba9599a7e63c?w=800&h=400&fit=crop', '[{"name": "LEITE CONDENSADO", "quantity": "1 por\u00e7\u00e3o/unidade"}, {"name": "MARACUJA", "quantity": "1 por\u00e7\u00e3o/unidade"}]', '47c981d3-ef57-420f-9d99-71c76b3b7d09', '2026-05-12T16:03:34.519038+00:00', NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.recipes ("id", "title", "description", "instructions", "category", "difficulty", "image_url", "ingredients", "author_id", "created_at", "source_url") VALUES ('66c6b292-c06c-4d2d-b8ef-2cde009abc34', 'Chef IA: MOUSSE DE MARACUJA Criativo', 'Esta receita foi cuidadosamente elaborada por nosso algoritmo de gastronomia para destacar os sabores de: MOUSSE DE MARACUJA
. Uma combinação harmoniosa de texturas e aromas para uma experiência única.', '1. Preparação Inicial: Comece organizando todos os ingredientes: MOUSSE DE MARACUJA
. Lave e corte os vegetais e proteínas em tamanhos uniformes.
2. Base de Sabor: Em uma panela aquecida com um fio de azeite, doure os ingredientes principais começando pelos que exigem mais tempo de cocção.
3. Desenvolvimento: Adicione os temperos de sua preferência e deixe os sabores se integrarem em fogo médio. Se necessário, adicione um pouco de água ou caldo para manter a umidade.
4. Finalização: Cozinhe até que a textura esteja ao seu gosto. Desligue o fogo e adicione ervas frescas por cima antes de servir.
5. Serviço: Disponha em um prato fundo para preservar o calor e finalize com um toque de pimenta moída na hora.', 'Inovação IA', 'Média', 'https://images.unsplash.com/photo-1546069901-ba9599a7e63c?w=800&h=400&fit=crop', '[{"name": "MOUSSE DE MARACUJA", "quantity": "1 por\u00e7\u00e3o/unidade"}]', '47c981d3-ef57-420f-9d99-71c76b3b7d09', '2026-05-12T16:04:57.323162+00:00', NULL) ON CONFLICT (id) DO NOTHING;

